// ============================================================
// JSONKB v1 — COMPANIES (Phase 5 Stub)
// Entity Type: misc
// Source Table: companies
// Hashing: clone-style stableStringify + FNV hash16 (NO crypto)
// IMPORTANT: JSONKB file path is NOT derived from kbdefaults.
//           kbdefaults is reserved for later markdown/link workflows.
// ============================================================

// ---------- input: Company detail ----------
const cItems = $items("Company – Detail");
if (!cItems || cItems.length === 0) {
  throw new Error('JSONKB Companies: Missing input from node "Company – Detail".');
}
const c = cItems[0].json;



// ---------- helpers ----------
function safeStr(v) {
  if (v === null || v === undefined) return null;
  const s = String(v).trim();
  return s.length ? s : null;
}

function boolish(v) {
  if (v === true || v === false) return v;
  if (v === 1 || v === 0) return Boolean(v);
  const s = String(v ?? '').toLowerCase();
  if (s === 'true' || s === '1' || s === 'yes') return true;
  if (s === 'false' || s === '0' || s === 'no') return false;
  return false;
}

// ---------- core identity ----------
const id   = c.id;
const name = safeStr(c.name) || '(Unknown Company)';
const slug =
  safeStr(c.slug) ||
  (safeStr(c.source_id) ? safeStr(c.source_id).replace(':', '-') : null);

if (!id) throw new Error('JSONKB Companies: company id is missing.');
if (!slug) throw new Error(`JSONKB Companies: slug is missing for ${name}.`);

const source    = safeStr(c.source) || 'uex';
const source_id = safeStr(c.source_id);

// ---------- uex_id (derived from source_id only; deterministic) ----------
let uex_id = null;
if (source_id && source_id.includes(':')) {
  const p = parseInt(source_id.split(':')[1], 10);
  if (!Number.isNaN(p)) uex_id = p;
}

// ---------- metadata (LOCKED: from companies.metadata via meta_*) ----------
const nickname                = safeStr(c.meta_nickname);
const industry                = safeStr(c.meta_industry);
const is_item_manufacturer    = boolish(c.meta_is_item_manufacturer);
const is_vehicle_manufacturer = boolish(c.meta_is_vehicle_manufacturer);

// ---------- vehicle count (from Company – Detail SQL) ----------
const vehicle_count = Number(c.vehicle_count ?? 0);

// ---------- entity_metadata ----------
const entity_metadata = {
  uex_company_id: uex_id,
  nickname,
  industry,
  is_item_manufacturer,
  is_vehicle_manufacturer,
  vehicle_count,
};

// ---------- kb_text (sentence-based, count-aware) ----------
const kb_text = [
  `${name}${nickname ? `, also known as ${nickname},` : ''} is a company` +
    (industry ? ` operating in the ${industry} industry` : '') +
    (is_vehicle_manufacturer ? ' that manufactures vehicles.' :
     is_item_manufacturer ? ' that manufactures items.' :
     '.'),
  vehicle_count > 0
    ? `It currently has ${vehicle_count} vehicle${vehicle_count === 1 ? '' : 's'} associated.`
    : null
].filter(Boolean).join(' ');

// ---------- kb_links (future-ready; DO NOT drive jsonkb_file_path from kbdefaults) ----------
const kb_links = {
  kb_page_path: `/kb/${slug}`,
  kb_browse_path: `/browse?category=company`,
};

// ---------- rag_hints (simple + cheap) ----------
const rag_hints = {
  sql_hints: [
    {
      name: 'vehicles_by_company',
      description: 'Vehicles manufactured by this company',
      sql:
`SELECT
  v.id   AS vehicle_id,
  v.name AS vehicle_name,
  v.slug,
  v.scu,
  v.is_spaceship,
  v.is_ground_vehicle
FROM vehicles v
WHERE v.company_uex_id = :company_source_id
ORDER BY v.name`,
      params: {
        company_source_id: source_id,
      },
    }
  ],
  notes: null,
};

// ---------- provenance ----------
const provenance = {
  generated_at: new Date().toISOString(),
  kb_generator_workflow: 'JSONKB - Companies (Phase5 Stub)',
  game_version: null,
  is_live_only: true,
  content_hash: null,
};

// ---------- build JSONKB ----------
const jsonkb = {
  kb_version: '1.0',

  entity_type: 'company',
  entity_id: id,
  entity_slug: slug,
  entity_name: name,

  source,
  source_id,
  source_table: 'companies',

  kb_text,
  kb_links,
  entity_metadata,
  rag_hints,
  provenance,
};

// ---------- stable stringify + hash16 (clone logic) ----------
function stableStringify(value) {
  const seen = new WeakSet();

  function norm(v) {
    if (v === null || v === undefined) return v;

    if (typeof v === 'object') {
      if (seen.has(v)) return null;
      seen.add(v);

      if (Array.isArray(v)) return v.map(norm);

      const out = {};
      for (const k of Object.keys(v).sort()) out[k] = norm(v[k]);
      return out;
    }
    return v;
  }

  return JSON.stringify(norm(value));
}

function fnv1a32Hex(str) {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = (hash + ((hash << 1) + (hash << 4) + (hash << 7) + (hash << 8) + (hash << 24))) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

function hash16(str) {
  const a = fnv1a32Hex(str);
  const b = fnv1a32Hex(str + '|v2');
  return a + b;
}

const hashBasis = stableStringify({
  entity_type: jsonkb.entity_type,
  entity_id: jsonkb.entity_id,
  kb_text: jsonkb.kb_text,
  entity_metadata: jsonkb.entity_metadata,
  rag_hints: jsonkb.rag_hints,
});

jsonkb.provenance.content_hash = hash16(hashBasis);

// ---------- JSONKB file path ----------
const jsonkb_file_path = `/kb/company/${slug}`;

// ---------- output ----------
return [
  {
    json: {
      company_id: id,
      slug,
      name,
      jsonkb,
      jsonkb_file_path,
    },
  },
];

